// src/core/soul.rs - Add swarm role field to Soul struct
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub enum SwarmRole {
    Architect,      // Teleological Weaver
    Bouncer,        // Integrity Gatekeeper (CAB)
    Archaeologist,  // Forensic Memory
    DevPair,        // Code Metabolism
    Specialist,     // Domain-specific (fallback)
}

// Add to Soul struct
pub swarm_role: Option<SwarmRole>,

// Add method to assign role based on traits and skills
pub fn assign_swarm_role(&mut self, task_type: TaskType) -> SwarmRole {
    match task_type {
        TaskType::Analytical | TaskType::Creative => {
            if self.traits.contains_key("teleological_thinking") {
                SwarmRole::Architect
            } else {
                SwarmRole::Specialist
            }
        }
        TaskType::Technical => {
            if self.skill_inventory.contains(&"code_review".to_string()) {
                SwarmRole::Bouncer
            } else {
                SwarmRole::DevPair
            }
        }
        TaskType::Negotiation => {
            if self.traits.contains_key("integrity_gatekeeping") {
                SwarmRole::Bouncer
            } else {
                SwarmRole::Specialist
            }
        }
    }
}

// src/core/swarm.rs - New orchestrator module
use crate::core::soul::{Soul, SwarmRole, TaskType};
use crate::core::state::CompanyState;

pub struct SwarmOrchestrator {
    agents: Vec<Soul>,
    state: CompanyState,
}

impl SwarmOrchestrator {
    pub fn new(agents: Vec<Soul>, state: CompanyState) -> Self {
        Self { agents, state }
    }

    /// Lehmann Framework: Assigns tasks based on role resonance
    pub fn assign_task(&mut self, task_type: TaskType, task_description: &str) -> Vec<(&Soul, f32)> {
        let mut assignments = Vec::new();

        for agent in &self.agents {
            let role = agent.assign_swarm_role(task_type);
            let resonance = agent.calculate_resonance(task_type);

            // Role-specific resonance multipliers
            let role_multiplier = match role {
                SwarmRole::Architect => 1.8,
                SwarmRole::Bouncer => 2.0,
                SwarmRole::Archaeologist => 1.5,
                SwarmRole::DevPair => 1.7,
                SwarmRole::Specialist => 1.2,
            };

            let effective_resonance = resonance * role_multiplier;
            assignments.push((agent, effective_resonance));
        }

        // Sort by resonance (descending)
        assignments.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
        assignments
    }

    /// Execute swarm coordination via ludic_crucible
    pub async fn run_strategic_crucible(&mut self, scenario: &str) -> anyhow::Result<Vec<String>> {
        use crate::core::ludic::LudicEngine;
        use crate::core::mind_palace::MindPalace;

        let mut mind_palace = MindPalace::new();
        let mut results = Vec::new();

        for agent in &self.agents {
            let result = LudicEngine::run_strategic_crucible(
                &agent.name,
                scenario,
                &self.state.status,
                &mut mind_palace
            )?;

            results.push(result.to_string());
        }

        Ok(results)
    }

    /// Thermodynamic efficiency metrics (V/LOC, J/tx, decisions/sec)
    pub fn calculate_efficiency_metrics(&self) -> (f64, f64, f64) {
        let value_per_loc = self.state.capital as f64 / self.state.total_lines_of_code as f64;
        let energy_per_tx = 0.0001; // Placeholder: actual J/tx measurement
        let decisions_per_sec = self.agents.len() as f64 * 0.5; // Placeholder

        (value_per_loc, energy_per_tx, decisions_per_sec)
    }
}
